"use client";

/**
 * Opener for the `contentHistory` overlay.
 *
 * - `useOpenContentHistoryViewer()` — imperative hook. Call to open with typed options;
 *   returns a handle with a `close()` method.
 * - `<ContentHistoryViewerController />` — declarative wrapper. Mount to open,
 *   unmount to close. Equivalent ergonomics to rendering a normal component.
 *
 * Generated by scripts/generate-overlay-controller.ts (`openers` mode).
 * Hand-edit freely after the initial seed; the script will not re-emit a
 * file that already exists unless invoked with --force.
 */

import { useCallback, useEffect } from "react";
import { useAppDispatch } from "@/lib/redux/hooks";
import { closeOverlay, openOverlay } from "@/lib/redux/slices/overlaySlice";

const OVERLAY_ID = "contentHistory" as const;

export interface OpenContentHistoryViewerOptions {
  /** Optional stable instance id. Omit to spawn a fresh instance. */
  instanceId?: string;
  sessionId: string;
  messageId: string;
}

export interface ContentHistoryViewerHandle {
  instanceId: string;
  close: () => void;
}

export function useOpenContentHistoryViewer() {
  const dispatch = useAppDispatch();
  return useCallback(
    (opts: OpenContentHistoryViewerOptions): ContentHistoryViewerHandle => {
      const instanceId = opts.instanceId ?? `contentHistory-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
      dispatch(
        openOverlay({
          overlayId: OVERLAY_ID,
          instanceId,
          data: {
            sessionId: opts.sessionId,
            messageId: opts.messageId,
          },
        }),
      );
      return {
        instanceId,
        close: () => dispatch(closeOverlay({ overlayId: OVERLAY_ID, instanceId })),
      };
    },
    [dispatch],
  );
}

/**
 * Declarative form. Renders nothing visible; opens the overlay on mount,
 * closes it on unmount. Use this when a caller wants to express overlay
 * state declaratively (the way they'd render a normal component).
 */
export function ContentHistoryViewerController(props: OpenContentHistoryViewerOptions): null {
  const open = useOpenContentHistoryViewer();
  useEffect(() => {
    const handle = open(props);
    return () => handle.close();
  }, [open, props.sessionId, props.messageId]);
  return null;
}
